# Dashboard UI constants — platform-aware font selection
if IS_WINDOWS:
    _FONT_FAMILY = "Segoe UI"
    _FONT_EMOJI_FAMILY = "Segoe UI Emoji"
else:
    _FONT_FAMILY = "Noto Sans"
    _FONT_EMOJI_FAMILY = "Noto Emoji"


def _build_fonts(size: int) -> tuple[tuple, tuple, tuple]:
    """Build (body, emoji, container) font tuples from a base size."""
    return (
        (_FONT_FAMILY, size),
        (_FONT_EMOJI_FAMILY, size + 3),
        (_FONT_FAMILY, max(size - 2, 6)),
    )


_COLOR_EMPTY_FG = "#666666"
_COLOR_CONTAINER_FG = "#888888"
_ROW_PAD_X = 1
_ROW_PAD_Y = 1

# Auto-contrast text colors (W3C contrast ratio + warm two-tone)
_TEXT_LIGHT = "#f5f0e8"  # warm white for dark backgrounds
_TEXT_DARK = "#1a1520"  # cool near-black for light backgrounds


def _load_title_emoji(*, row_height: int, bg_hex: str, label_width: int) -> tk.PhotoImage | None:
    """Load the chef kiss PNG centered in a canvas matching the emoji label width."""
    try:
        if config.TITLE_EMOJI_IMAGE.is_file():
            size = max(row_height - 6, 12)
            fg = Image.open(config.TITLE_EMOJI_IMAGE).convert("RGBA")
            fg.thumbnail((size, size), Image.Resampling.LANCZOS)
            bg_rgb = config.hex_to_rgb(hex_color=bg_hex)
            canvas = Image.new("RGBA", (label_width, size), bg_rgb + (255,))
            canvas.paste(
                fg,
                ((label_width - fg.width) // 2, (size - fg.height) // 2),
                fg,
            )
            return _pil_to_photoimage(canvas.convert("RGB"))
    except Exception:
        pass
    return None


def _pil_to_photoimage(pil_image: Any) -> tk.PhotoImage:
    """Convert a PIL Image to a Tkinter PhotoImage via PNG buffer."""
    buf = io.BytesIO()
    pil_image.save(buf, format="PNG")
    return tk.PhotoImage(data=buf.getvalue())


def _contrast_text_for_bg(bg_hex: str) -> str:
    """Pick light or dark text color based on W3C contrast ratio against bg."""
    r, g, b = config.hex_to_rgb(hex_color=bg_hex)

    def _srgb_linear(c: int) -> float:
        s = c / 255.0
        return s / 12.92 if s <= 0.03928 else ((s + 0.055) / 1.055) ** 2.4

    luminance = 0.2126 * _srgb_linear(r) + 0.7152 * _srgb_linear(g) + 0.0722 * _srgb_linear(b)
    ratio_light = 1.05 / (luminance + 0.05)
    ratio_dark = (luminance + 0.05) / 0.05
    return _TEXT_LIGHT if ratio_light > ratio_dark else _TEXT_DARK


