    def _on_cost_label_leave(self, event: Any):
        """Mouse left the cost label area — dismiss any open cost popup."""
        if self._cost_popup is not None:
            self._cost_popup.dismiss()
            self._cost_popup = None

    def _on_title_bar_right_click(self, event: Any):
        """Show Sessions submenu + Settings / Restart / Quit on title bar right-click."""
        self._title_menu.delete(0, tk.END)

        # Sessions submenu with visibility checkboxes
        sessions_submenu = tk.Menu(self._title_menu, tearoff=0)
        if self._on_build_sessions_menu:
            self._on_build_sessions_menu(sessions_submenu)
        self._title_menu.add_cascade(label="Sessions", menu=sessions_submenu)

        self._title_menu.add_separator()
        self._title_menu.add_command(
            label="Open...",
            command=self._on_open_folder if self._on_open_folder else lambda: None,
        )
        self._title_menu.add_separator()
        self._title_menu.add_command(
            label="Settings",
            command=self._on_settings if self._on_settings else lambda: None,
        )
        self._title_menu.add_command(
            label="Restart",
            command=self._on_restart if self._on_restart else lambda: None,
        )
        self._title_menu.add_command(
            label="Quit",
            command=self._on_quit if self._on_quit else lambda: None,
        )
        self._title_menu.tk_popup(event.x_root, event.y_root)
        return "break"

    def update_title_bar(
        self,
        *,
        daily_cost: float,
        limits: dict,
        visible_count: int = 0,
        total_count: int = 0,
    ):
        """Update the title bar with current cost and limit data."""
        bg = self._title_bg
        fg = self._title_fg

        hidden_count = total_count - visible_count
        if hidden_count > 0:
            self._title_text_label.configure(text=f"{config.TITLE_TEXT} (+{hidden_count})")
        else:
            self._title_text_label.configure(text=config.TITLE_TEXT)

        # Right-side info
        cost_text = f"${daily_cost:.2f}" if daily_cost > 0 else ""
        self._title_cost_label.configure(text=cost_text, fg=fg, bg=bg)

        five_hour = limits.get("five_hour", {})
        seven_day = limits.get("seven_day", {})

        five_util = five_hour.get("utilization") if isinstance(five_hour, dict) else None
        seven_util = seven_day.get("utilization") if isinstance(seven_day, dict) else None

        self._title_5h_label.configure(
            text=f"5h: {five_util:.0f}%" if five_util is not None else "",
            fg=fg,
            bg=bg,
        )
        self._title_7d_label.configure(
            text=f"7d: {seven_util:.0f}%" if seven_util is not None else "",
            fg=fg,
            bg=bg,
        )

        # Update title bar height
        try:
            self._title_bar.configure(height=self._settings.row_height)
        except tk.TclError:
            pass

