    def apply_settings(self, settings: Settings, *, restore_position: bool = False):
        """Apply settings to the window. Does NOT change position unless restore_position=True."""
        self._settings = settings
        self._font_body, self._font_emoji, self._font_container = _build_fonts(settings.font_size)
        self._force_resize = True
        self._icon_cache.clear()

        # Update title bar emoji (image or font)
        new_emoji_image = _load_title_emoji(
            row_height=settings.row_height,
            bg_hex=self._title_bg,
            label_width=self._emoji_label_width,
        )
        if new_emoji_image:
            self._title_emoji_image = new_emoji_image
            self._title_emoji_label.configure(image=self._title_emoji_image)
        else:
            self._title_emoji_label.configure(font=self._font_emoji)
        self._title_text_label.configure(font=self._font_body)
        self._title_cost_label.configure(font=self._font_body)
        self._title_7d_label.configure(font=self._font_body)
        self._title_5h_label.configure(font=self._font_body)

        # Window attributes
        self._window.wm_attributes("-topmost", bool(settings.always_on_top))
        self._window.configure(bg=settings.window_bg)
        self._frame.configure(bg=settings.window_bg)
        self._empty_label.configure(bg=settings.window_bg, font=self._font_body)

        # Position — only on initial startup, not on settings changes
        if restore_position:
            x = settings.window_x
            y = settings.window_y
            if x is not None and y is not None:
                # Sanity check: discard positions entirely off-screen
                # (e.g., from a disconnected monitor). Don't clamp to
                # edges — that shifts the window on every restart.
                screen_w = self._root.winfo_screenwidth()
                screen_h = self._root.winfo_screenheight()
                if x < -screen_w or x > 2 * screen_w or y < -screen_h or y > 2 * screen_h:
                    x, y = 0, 0
                if settings.grow_up:
                    # y is the saved bottom edge — will be adjusted in
                    # update_sessions once we know the actual height
                    self._grow_up_bottom_y = y
                self._window.geometry(f"{settings.row_width}x1+{x}+{y}")
            else:
                self._window.geometry(f"{settings.row_width}x1")

    # ------------------------------------------------------------------
    # Window visibility
    # ------------------------------------------------------------------

    def show(self):
        self._window.deiconify()

    def hide(self):
        self._save_position()
        self._window.withdraw()

    @property
    def toplevel(self) -> tk.Toplevel:
        return self._window

    def get_position(self) -> tuple[int | None, int | None]:
        """Return the window position to save.

        When grow_up is enabled, saves the bottom edge y-coordinate
        so the bottom stays anchored across restarts with different
        session counts.

        Returns (None, None) if the window reports nonsensical values
        (e.g. Wayland returning 0,0 for overrideredirect windows) to
        avoid corrupting the saved position.
        """
        try:
            x = self._window.winfo_x()
            y = self._window.winfo_y()
            h = self._window.winfo_height()
            # Reject bogus geometry: a 1px-tall window at origin means the
            # compositor isn't reporting real values (common on Wayland).
            if x == 0 and y == 0 and h <= 1:
                return None, None
            if self._settings.grow_up:
                y = y + h
            return x, y
        except tk.TclError:
            return None, None

    # ------------------------------------------------------------------
    # Drag (borderless window)
    # ------------------------------------------------------------------

    _DRAG_THRESHOLD = 5  # pixels of movement before it counts as a drag

    def _on_drag_start(self, event: Any):
        self._drag_start_x = event.x
        self._drag_start_y = event.y
        self._dragged = False

    def _on_drag_motion(self, event: Any):
        dx = abs(event.x - self._drag_start_x)
        dy = abs(event.y - self._drag_start_y)
        if dx > self._DRAG_THRESHOLD or dy > self._DRAG_THRESHOLD:
            self._dragged = True
        if self._dragged:
            x = self._window.winfo_x() + event.x - self._drag_start_x
            y = self._window.winfo_y() + event.y - self._drag_start_y
            self._window.geometry(f"+{x}+{y}")

    # ------------------------------------------------------------------
    # Right-click context menu
    # ------------------------------------------------------------------

    def _on_right_click_event(self, event: Any):
        if self._on_right_click:
            self._on_right_click(event.x_root, event.y_root)
        return "break"

    # ------------------------------------------------------------------
    # Position persistence
    # ------------------------------------------------------------------

    def _save_position(self):
        if self._on_position_save:
            x, y = self.get_position()
            if x is not None and y is not None:
                self._on_position_save(x, y)

    # ------------------------------------------------------------------
    # Session rows
    # ------------------------------------------------------------------

    def update_sessions(self, sessions: list[SessionRow]):
        # When shaded, track rows silently but don't touch geometry or visibility
        if self._shaded:
            current_pids = {row.session.pid for row in sessions}
            for pid in set(self._rows.keys()) - current_pids:
                self._remove_row(pid)
            for row in sessions:
                if row.session.pid in self._rows:
                    self._update_row(row)
                else:
                    self._add_row(row)
                    self._rows[row.session.pid]["frame"].pack_forget()
            self._row_order = [row.session.pid for row in sessions]
            return

        current_pids = {row.session.pid for row in sessions}
        changed = False

        # Remove stale rows
        for pid in set(self._rows.keys()) - current_pids:
            self._remove_row(pid)
            changed = True

        # Add or update rows
        for row in sessions:
            if row.session.pid in self._rows:
                self._update_row(row)
            else:
                self._add_row(row)
                changed = True

        # Re-order rows only if the order changed
        desired_order = [row.session.pid for row in sessions]
        if desired_order != self._row_order:
            for sr in sessions:
                row_data = self._rows.get(sr.session.pid)
                if row_data:
                    row_data["frame"].pack_forget()
                    row_data["frame"].pack(fill=tk.X, padx=_ROW_PAD_X, pady=_ROW_PAD_Y)
            self._row_order = desired_order
            changed = True

        # Empty state label
        if sessions:
            self._empty_label.pack_forget()
        else:
            self._empty_label.pack(pady=10)

        # Only recalculate geometry when rows were added/removed/reordered
        if not changed and not self._force_resize:
            return
        self._force_resize = False

        # Resize height, preserve position (or anchor bottom edge if grow_up)
        self._window.update_idletasks()
        old_height = self._window.winfo_height()
        title_bar_height = self._settings.row_height + _ROW_PAD_Y * 2
        if sessions:
            new_height = title_bar_height + len(sessions) * (
                self._settings.row_height + _ROW_PAD_Y * 2
            )
        else:
            new_height = title_bar_height + self._settings.row_height + _ROW_PAD_Y * 2
        x = self._window.winfo_x()
        y = self._window.winfo_y()

        if self._settings.grow_up:
            # First render after startup: use saved bottom edge
            bottom_y = getattr(self, "_grow_up_bottom_y", None)
            if bottom_y is not None:
                y = bottom_y - new_height
                del self._grow_up_bottom_y
            elif old_height > 0:
                # Subsequent renders: keep bottom edge fixed
                y = y + old_height - new_height

        # Clamp to keep window on-screen (grow_up can compute negative y;
        # Wayland can report bogus positions that drift off-screen)
        screen_w = self._root.winfo_screenwidth()
        screen_h = self._root.winfo_screenheight()
        if x < 0:
            x = 0
        elif x > screen_w - 50:
            x = max(screen_w - self._settings.row_width, 0)
        if y < 0:
            y = 0
        elif y > screen_h - 50:
            y = max(screen_h - new_height, 0)

        self._window.geometry(f"{self._settings.row_width}x{new_height}+{x}+{y}")

    def _color_for_state(self, state: StatusState) -> str:
        return {
            StatusState.WORKING: self._settings.color_working,
            StatusState.READY: self._settings.color_ready,
            StatusState.IDLE: self._settings.color_idle,
            StatusState.AWAITING_INPUT: self._settings.color_awaiting_input,
            StatusState.PERMISSION_REQUIRED: self._settings.color_permission_required,
        }.get(state, self._settings.color_idle)

    def _emoji_for_state(self, state: StatusState) -> str:
        return {
            StatusState.WORKING: self._settings.emoji_working,
            StatusState.READY: self._settings.emoji_ready,
            StatusState.IDLE: self._settings.emoji_idle,
            StatusState.AWAITING_INPUT: self._settings.emoji_awaiting_input,
            StatusState.PERMISSION_REQUIRED: self._settings.emoji_permission_required,
        }.get(state, self._settings.emoji_idle)

    def _container_label(self, container: ContainerInfo | None) -> str:
        if not container or container.container_type == ContainerType.UNKNOWN:
            return ""
        return {
            ContainerType.VSCODE: "VS Code",
            ContainerType.TERMINAL: "Term",
            ContainerType.GITBASH: "Git Bash",
            ContainerType.SCREEN: "screen",
        }.get(container.container_type, container.container_type.value)

    def _cwd_display(self, cwd: str, agent_count: int = 0) -> str:
        display = cwd_relative_to_home(cwd=cwd)
        if agent_count > 0:
            display += f" (+{agent_count})"
        return display

    @staticmethod
    def _branch_display(branch: str) -> str:
        return f"[{branch}]" if branch else ""

    @staticmethod
    def _branch_color(*, merged: bool, fg: str) -> str:
        if merged:
            return config.DEFAULT_COLOR_BRANCH_MERGED
        return fg

    def _flag_icon(self, row: SessionRow) -> tk.PhotoImage:
        """Generate an eye icon for git status + manual flag, or transparent if clean."""
        icon_size = max(self._settings.row_height - 8, 16)
        eye_color = self._git_status_color(row)
        pupil_color_hex = self._settings.color_flag_manual if row.flagged else None

        cache_key = (eye_color, pupil_color_hex, icon_size)
        cached = self._icon_cache.get(cache_key)
        if cached is not None:
            return cached

        if eye_color is None and pupil_color_hex is None:
            # No git status, no flag — transparent placeholder
            blank = Image.new("RGBA", (icon_size, icon_size), (0, 0, 0, 0))
            result = _pil_to_photoimage(blank)
        else:
            # Eye outer = git status, pupil = manual flag
            # If only flagged (no git status), use neutral gray eye with flag-colored pupil
            eye_rgb = config.hex_to_rgb(hex_color=eye_color) if eye_color else (90, 90, 90)

            if pupil_color_hex is not None:
                img = generate_icon_image(
                    color=eye_rgb, pupil_color=config.hex_to_rgb(hex_color=pupil_color_hex)
                )
            else:
                img = generate_icon_image(color=eye_rgb)
            result = _pil_to_photoimage(img.resize((icon_size, icon_size)))

        self._icon_cache[cache_key] = result
        return result

    def _git_status_color(self, row: SessionRow) -> str | None:
        """Return color for git working tree status (excludes manual flag)."""
        if row.git_status == GitStatus.UNSTAGED_CHANGES:
            return self._settings.color_flag_unstaged
        if row.git_status == GitStatus.STAGED_UNCOMMITTED:
            return self._settings.color_flag_staged
        if row.git_status == GitStatus.COMMITTED_NOT_PUSHED:
            return self._settings.color_flag_unpushed
        if row.git_status == GitStatus.PUSHED_NOT_MERGED:
            return self._settings.color_flag_unmerged
        return None

    def _add_row(self, row: SessionRow):
        session = row.session
        state = row.state
        container = row.container

        if row.unattached:
            bg = self._settings.color_unattached
            fg = _COLOR_CONTAINER_FG  # dim text for ghosts
            emoji = self._settings.emoji_unattached
            container_text = ""
        else:
            bg = self._color_for_state(state)
            fg = _contrast_text_for_bg(bg)
            emoji = self._emoji_for_state(state)
            container_text = self._container_label(container)

        row_frame = tk.Frame(self._frame, bg=bg, height=self._settings.row_height, cursor="hand2")
        row_frame.pack(fill=tk.X, padx=1, pady=1)
        row_frame.pack_propagate(False)

        # Pack LEFT: flag eye icon → emoji (visual indicators grouped together)
        flag_image = self._flag_icon(row)
        flag_label = tk.Label(
            row_frame,
            image=flag_image,
            bg=bg,
            anchor=tk.CENTER,
        )
        flag_label.pack(side=tk.LEFT, padx=(6, 0))

        status_var = tk.StringVar(value=emoji)
        status_label = tk.Label(
            row_frame,
            textvariable=status_var,
            bg=bg,
            fg=fg,
            font=self._font_emoji,
            width=2,
            anchor=tk.CENTER,
        )
        status_label.pack(side=tk.LEFT, padx=(0, 2))

        # Pack RIGHT: container label
        container_var = tk.StringVar(value=container_text)
        container_label = tk.Label(
            row_frame,
            textvariable=container_var,
            bg=bg,
            fg=_COLOR_CONTAINER_FG,
            font=self._font_container,
            anchor=tk.E,
        )
        container_label.pack(side=tk.RIGHT, padx=(0, 6))

        cwd_var = tk.StringVar(value=self._cwd_display(session.cwd, row.agent_count))
        cwd_label = tk.Label(
            row_frame,
            textvariable=cwd_var,
            bg=bg,
            fg=fg,
            font=self._font_body,
            anchor=tk.W,
        )
        cwd_label.pack(side=tk.LEFT, padx=(2, 0))

        branch_var = tk.StringVar(value=self._branch_display(row.branch))
        branch_fg = self._branch_color(merged=row.merged, fg=fg)
        branch_label = tk.Label(
            row_frame,
            textvariable=branch_var,
            bg=bg,
            fg=branch_fg,
            font=self._font_body,
            anchor=tk.W,
        )
        branch_label.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(2, 0))

        # Click and right-click bindings on all widgets
        widgets = [row_frame, status_label, cwd_label, branch_label, container_label, flag_label]

        def make_click(s: SessionInfo = session):
            def handler(event: Any):
                if self._double_clicked_pid == s.pid:
                    self._double_clicked_pid = None
                    return
                if not self._dragged and self._on_row_left_click:
                    # Delay single-click so double-click can suppress it.
                    # On Linux, <ButtonRelease-1> fires before <Double-1>,
                    # so without a delay the single-click runs first.
                    def deferred_click(session: SessionInfo = s):
                        self._pending_click_id = None
                        self._pending_click_pid = None
                        if self._double_clicked_pid != session.pid and self._on_row_left_click:
                            self._on_row_left_click(session)
                        self._double_clicked_pid = None

                    self._pending_click_id = self._window.after(200, deferred_click)
                    self._pending_click_pid = s.pid

            return handler

        def make_double_click(s: SessionInfo = session):
            def handler(event: Any):
                self._double_clicked_pid = s.pid
                if self._pending_click_id is not None:
                    self._window.after_cancel(self._pending_click_id)
                    self._pending_click_id = None
                    self._pending_click_pid = None
                if self._on_row_double_click:
                    self._on_row_double_click(s)
                return "break"

            return handler

        def make_middle_click(s: SessionInfo = session):
            def handler(event: Any):
                if self._on_row_middle_click:
                    self._on_row_middle_click(s)

            return handler

        def make_right_click(s: SessionInfo = session):
            def handler(event: Any):
                if self._on_row_right_click:
                    self._on_row_right_click(s, event.x_root, event.y_root)
                return "break"

            return handler

        click = make_click()
        dbl_click = make_double_click()
        mid_click = make_middle_click()
        right_click = make_right_click()
        for w in widgets:
            w.bind("<Button-1>", self._on_drag_start)
            w.bind("<B1-Motion>", self._on_drag_motion)
            w.bind("<ButtonRelease-1>", click)
            w.bind("<Double-1>", dbl_click)
            w.bind("<Button-2>", mid_click)
            w.bind("<Button-3>", right_click)

        self._rows[session.pid] = {
            "frame": row_frame,
            "status_var": status_var,
            "cwd_var": cwd_var,
            "branch_var": branch_var,
            "container_var": container_var,
            "status_label": status_label,
            "cwd_label": cwd_label,
            "branch_label": branch_label,
            "container_label": container_label,
            "flag_label": flag_label,
            "flag_image": flag_image,
        }

    def _update_row(self, row_data: SessionRow):
        row = self._rows[row_data.session.pid]

        if row_data.unattached:
            bg = self._settings.color_unattached
            fg = _COLOR_CONTAINER_FG
            emoji = self._settings.emoji_unattached
            container_text = ""
        else:
            bg = self._color_for_state(row_data.state)
            fg = _contrast_text_for_bg(bg)
            emoji = self._emoji_for_state(row_data.state)
            container_text = self._container_label(row_data.container)

        row["status_var"].set(emoji)
        row["cwd_var"].set(self._cwd_display(row_data.session.cwd, row_data.agent_count))
        row["branch_var"].set(self._branch_display(row_data.branch))
        row["container_var"].set(container_text)
        row["cwd_label"].configure(fg=fg, font=self._font_body)
        row["branch_label"].configure(
            fg=self._branch_color(merged=row_data.merged, fg=fg), font=self._font_body
        )
        row["status_label"].configure(font=self._font_emoji)
        row["container_label"].configure(font=self._font_container)
        flag_image = self._flag_icon(row_data)
        row["flag_image"] = flag_image  # prevent GC
        row["flag_label"].configure(image=flag_image, bg=bg)

        # Update row height if settings changed
        try:
            row["frame"].configure(height=self._settings.row_height)
        except tk.TclError:
            pass

        for key in (
            "frame",
            "status_label",
            "cwd_label",
            "branch_label",
            "container_label",
            "flag_label",
        ):
            try:
                row[key].configure(bg=bg)
            except tk.TclError:
                pass

    def _remove_row(self, pid: int):
        if self._pending_click_pid == pid and self._pending_click_id is not None:
            self._window.after_cancel(self._pending_click_id)
            self._pending_click_id = None
            self._pending_click_pid = None
        row = self._rows.pop(pid, None)
        if row and row["frame"]:
            row["frame"].destroy()
